  /* ============== 空（大気散乱スカイ THREE.Sky） ============== */
  // Rayleigh/Mie 散乱で本物の昼空を再現。太陽グロー・地平線のヘイズ・天頂の深い青が出る。
  const sky = new Sky();
  sky.scale.setScalar(10000);
  sky.frustumCulled = false; // far=1200 でもカリングされない（シェーダ側で常に最遠面へ描画するため大きさは見た目に影響しない）
  {
    const u = sky.material.uniforms;
    u.turbidity.value = 4;          // 大気の濁り（低いほど澄んだ青）
    u.rayleigh.value = 2.2;         // 青の散乱量（天頂の青さ）
    u.mieCoefficient.value = 0.005; // 太陽周りのもや
    u.mieDirectionalG.value = 0.82; // 太陽グローの締まり
    u.sunPosition.value.copy(SUN_OFFSET).normalize(); // 太陽の見た目をライト/影の方向に一致させる
  }
  scene.add(sky);
  // THREE.Sky はトーンマッピング無しだと白飛びするため屋外では使わず、自前のグラデーション空ドームで描く。
  sky.visible = false;
  const skyGradCv = document.createElement('canvas'); skyGradCv.width = 1; skyGradCv.height = 128;
  const skyGradCtx = skyGradCv.getContext('2d');
  const skyGradTex = new THREE.CanvasTexture(skyGradCv); skyGradTex.colorSpace = THREE.SRGBColorSpace;
  const skyDome = new THREE.Mesh(new THREE.SphereGeometry(800, 32, 20),
    new THREE.MeshBasicMaterial({ map: skyGradTex, side: THREE.BackSide, fog: false, depthWrite: false }));
  skyDome.frustumCulled = false; skyDome.renderOrder = -10; scene.add(skyDome);
  // 太陽（やわらかいグロー）
  const sunGlowTex = (() => {
    const N = 128, cc = document.createElement('canvas'); cc.width = cc.height = N; const gg = cc.getContext('2d');
    const grd = gg.createRadialGradient(N / 2, N / 2, 0, N / 2, N / 2, N / 2);
    grd.addColorStop(0, 'rgba(255,255,255,1)'); grd.addColorStop(0.1, 'rgba(255,255,255,0.92)');
    grd.addColorStop(0.32, 'rgba(255,255,255,0.28)'); grd.addColorStop(1, 'rgba(255,255,255,0)');
    gg.fillStyle = grd; gg.fillRect(0, 0, N, N);
    const t = new THREE.CanvasTexture(cc); t.colorSpace = THREE.SRGBColorSpace; return t;
  })();
  const sunGlow = new THREE.Sprite(new THREE.SpriteMaterial({ map: sunGlowTex, color: 0xfff2da, transparent: true, blending: THREE.AdditiveBlending, depthWrite: false, fog: false, opacity: 0.9 }));
  sunGlow.scale.set(150, 150, 1); sunGlow.renderOrder = -9; scene.add(sunGlow);
  // —— 雲：空ドームと同心の“雲ドーム”に焼き込む（ビルボードは視点回転で泳ぐ＆半透明が重なって泡に見えるため不採用） ——
  function makeCloudPano() {
    const W = 2048, H = 1024, c = document.createElement('canvas'); c.width = W; c.height = H;
    const g = c.getContext('2d');
    let s = 20240624 >>> 0; const rr = () => { s = (s * 1664525 + 1013904223) >>> 0; return s / 4294967296; };
    const horizonY = H * 0.53;
    const clouds = []; // {cx,baseY,sc,parts,top,halfW}
    const make = (cx, baseY, sc) => {
      const Wc = (150 + rr() * 130) * sc, Hc = (62 + rr() * 78) * sc, parts = [], n = 15 + (rr() * 9 | 0);
      for (let i = 0; i < n; i++) {
        const u = rr() * 2 - 1, env = Math.sqrt(Math.max(0, 1 - u * u * 0.9)); // 楕円の上端エンベロープ
        const y = -rr() * rr() * Hc * env;                                     // 下に密・上ほどまばら
        const r = (15 + rr() * 20) * sc * (0.6 + 0.4 * env);                   // 中央ほど大きい
        parts.push([u * Wc * 0.5, y, r]);
      }
      const nb = 4 + (rr() * 2 | 0); // 平らな底をしっかり塗る大円
      for (let i = 0; i < nb; i++) parts.push([((i / (nb - 1)) - 0.5) * Wc * 0.82, -rr() * 8 * sc, (26 + rr() * 16) * sc]);
      let top = 0; for (const p of parts) top = Math.min(top, p[1] - p[2]);
      clouds.push({ cx, baseY, sc, parts, top, halfW: Wc * 0.62 });
    };
    // クラスター配置でメリハリ（大きな塊＋広い青空のすき間）
    const clusters = 3 + (rr() * 2 | 0);
    for (let k = 0; k < clusters; k++) {
      const baseX = rr() * W, grp = 1 + (rr() * 3 | 0), big = 0.85 + rr() * 1.1;
      for (let j = 0; j < grp; j++) make(baseX + (rr() - 0.5) * 250, horizonY - rr() * 30, big * (0.7 + rr() * 0.5));
    }
    for (let i = 0; i < 3; i++) if (rr() < 0.7) make(rr() * W, horizonY - rr() * 40, 0.5 + rr() * 0.4); // まばらな小雲
    for (let i = 0; i < 3; i++) make(rr() * W, horizonY - 150 - rr() * 110, 0.4 + rr() * 0.3);          // 高めの小雲
    g.fillStyle = '#ffffff'; // パス1：各雲をソリッドに塗りつぶす（縁だけ軽くぼかす）。横ループ対応
    for (const cl of clouds) for (const off of [-W, 0, W]) {
      g.save(); g.filter = 'blur(1.5px)';
      for (const [dx, dy, r] of cl.parts) { g.beginPath(); g.arc(cl.cx + off + dx, cl.baseY + dy, r, 0, 6.2832); g.fill(); }
      g.restore();
    }
    g.globalCompositeOperation = 'source-atop'; // パス2：雲ごとに上=陽光/下=青影の縦グラデ（滑らかな立体感・継ぎ目なし）
    for (const cl of clouds) {
      const topY = cl.baseY + cl.top, botY = cl.baseY + 16 * cl.sc, halfW = cl.halfW;
      const gd = g.createLinearGradient(0, topY, 0, botY);
      gd.addColorStop(0, 'rgba(255,255,255,0.45)'); gd.addColorStop(0.55, 'rgba(255,255,255,0.0)'); gd.addColorStop(1, 'rgba(156,178,206,0.62)');
      g.fillStyle = gd;
      for (const off of [-W, 0, W]) g.fillRect(cl.cx + off - halfW, topY - 10, halfW * 2, botY - topY + 30);
    }
    const hg = g.createLinearGradient(0, horizonY - 240, 0, horizonY); // パス3：左上からのやわらかい陽光ハイライト
    hg.addColorStop(0, 'rgba(255,255,248,0.26)'); hg.addColorStop(1, 'rgba(255,255,255,0)');
    g.fillStyle = hg; g.fillRect(0, 0, W, H);
    g.globalCompositeOperation = 'destination-out'; // 雲底を平らに（地平線下は透明＝空が見える）
    const eg = g.createLinearGradient(0, horizonY - 6, 0, horizonY + 56); eg.addColorStop(0, 'rgba(0,0,0,0)'); eg.addColorStop(1, 'rgba(0,0,0,1)');
    g.fillStyle = eg; g.fillRect(0, 0, W, H);
    g.globalCompositeOperation = 'source-over';
    const t = new THREE.CanvasTexture(c); t.colorSpace = THREE.SRGBColorSpace; t.wrapS = THREE.RepeatWrapping; t.anisotropy = 4; return t;
  }
  const cloudDome = new THREE.Mesh(new THREE.SphereGeometry(700, 48, 32),
    new THREE.MeshBasicMaterial({ map: makeCloudPano(), side: THREE.BackSide, transparent: true, depthWrite: false, fog: false, opacity: 0.95 }));
  cloudDome.renderOrder = -9; cloudDome.frustumCulled = false; cloudDome.visible = false; // 実写パノラマに置き換え（手描き雲は不使用）
  // —— 実写パノラマ空（Poly Haven CC0 HDRI を LDR 化した equirectangular 写真）。晴れ↔曇りの2枚を天候でクロスフェード ——
  const SKY_DAY_URI = 'data:image/jpeg;base64,';
  const SKY_OVERCAST_URI = 'data:image/jpeg;base64,';
  const _texLoader = new THREE.TextureLoader();
  let skyReady = false; // 写真テクスチャのデコード完了まで背後の青い空ドームを見せる（読込中の黒画面を防ぐ）
  const loadSkyTex = (url, cb) => { const t = _texLoader.load(url, cb); t.colorSpace = THREE.SRGBColorSpace; t.wrapS = THREE.RepeatWrapping; t.anisotropy = 4; return t; };
  const photoSkyGeo = new THREE.SphereGeometry(760, 48, 32);
  const photoSky = new THREE.Mesh(photoSkyGeo,
    new THREE.MeshBasicMaterial({ map: loadSkyTex(SKY_DAY_URI, () => { skyReady = true; }), side: THREE.BackSide, depthWrite: false, fog: false }));
  photoSky.renderOrder = -9; photoSky.frustumCulled = false; photoSky.rotation.y = SKY_ROT_Y; scene.add(photoSky);
  const photoOvercast = new THREE.Mesh(photoSkyGeo,
    new THREE.MeshBasicMaterial({ map: loadSkyTex(SKY_OVERCAST_URI), side: THREE.BackSide, depthWrite: false, fog: false, transparent: true, opacity: 0 }));
  photoOvercast.renderOrder = -8; photoOvercast.frustumCulled = false; photoOvercast.rotation.y = SKY_ROT_Y; scene.add(photoOvercast);
  const SUN_DIR = SUN_OFFSET.clone().normalize();
  const _skyTop = new THREE.Color(), _skyMid = new THREE.Color(), _skyHor = new THREE.Color();
  function updateSkyDome(flash) {
    // wCur の空色からグラデーションを焼き直す（1x128 の小テクスチャなので毎フレームでも軽い）
    _skyTop.copy(wCur.skyTop).lerp(WHITE, flash * 0.5);
    _skyMid.copy(wCur.skyMid).lerp(WHITE, flash * 0.5);
    _skyHor.copy(wCur.skyHor).lerp(WHITE, flash * 0.5);
    const grd = skyGradCtx.createLinearGradient(0, 0, 0, 128);
    grd.addColorStop(0.0, '#' + _skyTop.getHexString());
    grd.addColorStop(0.40, '#' + _skyMid.getHexString());
    grd.addColorStop(0.50, '#' + _skyHor.getHexString());
    grd.addColorStop(1.0, '#' + _skyHor.getHexString());
    skyGradCtx.fillStyle = grd; skyGradCtx.fillRect(0, 0, 1, 128);
    skyGradTex.needsUpdate = true;
    skyDome.position.copy(camera.position);
    sunGlow.position.copy(camera.position).addScaledVector(SUN_DIR, 700);
    sunGlow.material.color.copy(wCur.sunCol);
    sunGlow.material.opacity = Math.min(1, wCur.glow + flash * 0.5);
  }
